async function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

async function verifyImageUrl(url) {
  try {
    const response = await fetch(url, { method: 'HEAD', timeout: 15000 });
    return response.ok && response.headers.get('content-type')?.startsWith('image/');
  } catch {
    return false;
  }
}

async function main() {
  console.log('Signing in anonymously...');
  await signInAnonymously(auth);
  console.log('Signed in. Starting pre-cache of', ITEMS.length, 'images...\n');

  let cached = 0, skipped = 0, failed = 0;

  for (let i = 0; i < ITEMS.length; i++) {
    const { id, url } = ITEMS[i];
    process.stdout.write(`[${i + 1}/${ITEMS.length}] ${id} ... `);

    // Check if already cached
    const docRef = doc(db, CACHE_COLLECTION, id);
    const existing = await getDoc(docRef);
    if (existing.exists()) {
      console.log('already cached, skipping');
      skipped++;
      continue;
    }

    // Verify image actually loads
    const ok = await verifyImageUrl(url);
    if (!ok) {
      console.log('FAILED (image did not load)');
      failed++;
      await sleep(DELAY_MS);
      continue;
    }

    // Write to Firestore
    await setDoc(docRef, { botId: id, url, prompt: id, createdAt: serverTimestamp() });
    console.log('cached ✓');
    cached++;

    // Polite delay between requests
    await sleep(DELAY_MS);
  }

  console.log(`\nDone! Cached: ${cached}, Skipped (already done): ${skipped}, Failed: ${failed}`);
  process.exit(0);
}

main().catch(err => { console.error(err); process.exit(1); });
